# Configuration constants
# CRITICAL FIX (Jan 10, 2026): Further reduced market scanning to prevent 429/403 rate limit errors
# Coinbase has strict rate limits (~10 req/s burst, lower sustained)
# Instead of scanning all 730 markets every cycle, we batch scan smaller subsets
# RateLimiter enforces 10 req/min (6s between calls), so we must scan fewer markets
MARKET_SCAN_LIMIT = 30   # Scan 30 markets per cycle for better opportunity discovery
                         # This rotates through different markets each cycle
                         # Complete scan of 730 markets takes ~24 cycles (~60 minutes)
                         # Increased from 15 to find 2x more trading opportunities while respecting rate limits
MIN_CANDLES_REQUIRED = 90  # Minimum candles needed for analysis (relaxed from 100 to prevent infinite sell loops)

# Rate limiting constants (prevent 429 errors from Coinbase API)
# UPDATED (Jan 10, 2026): CRITICAL FIX - Aligned delays with RateLimiter to prevent rate limits
# Coinbase rate limits: ~10 requests/second burst, but sustained rate must be much lower
# Real-world testing shows we need to be even more conservative to avoid 403 "too many errors"
# RateLimiter enforces 6s minimum between get_candles calls (10 req/min)
# Manual delay must be >= 6s to avoid conflicts and ensure proper rate limiting
POSITION_CHECK_DELAY = 0.5  # 500ms delay between position checks (was 0.3s)
SELL_ORDER_DELAY = 0.7      # 700ms delay between sell orders (was 0.5s)
# LATENCY OPTIMISATION: MARKET_SCAN_DELAY is the dominant cycle cost.
# Default 8.0s safely clears the RateLimiter floor (6s minimum) with a 2s buffer.
# Operators can lower to 6.5s via env-var NIJA_MARKET_SCAN_DELAY (min 6.0s enforced).
# At 30 markets: 8.0s→240s vs 6.5s→195s — saves ~45s per cycle.
try:
    _raw_scan_delay = float(os.environ.get("NIJA_MARKET_SCAN_DELAY", "8.0"))
except (ValueError, TypeError):
    import logging as _logging
    _logging.getLogger(__name__).warning(
        "NIJA_MARKET_SCAN_DELAY has an invalid value; defaulting to 8.0s"
    )
    _raw_scan_delay = 8.0
MARKET_SCAN_DELAY = max(6.0, _raw_scan_delay)  # Hard floor: never below RateLimiter minimum
                            # CRITICAL: Must be >= 7.5s to align with RateLimiter (8 req/min for get_candles)
                            # The 0.5s buffer (8.0s vs 7.5s) accounts for jitter and processing time
                            # At 8.0s delay, we scan at ~0.125 req/s which prevents both 429 and 403 errors
                            # At 5-15 markets per cycle with 8.0s delay, scanning takes 40-120 seconds
                            # This conservative rate ensures API key never gets temporarily blocked

# Broker balance fetch timeout constants
# Increased from 15s → 30s → 60s because Kraken API can be slow under load and was
# timing out before a valid response arrived, causing the bot to fall back to
# monitor mode. 60s gives the API enough headroom to respond during peak congestion
# periods (connection timeouts were observed at 30s threshold).
# Cached balance (max age: 90s) is still used as an immediate fallback when the
# live fetch times out.
BALANCE_FETCH_TIMEOUT = 60  # Hard timeout for balance API call (increased to 60s to prevent Kraken connection timeouts)
CACHED_BALANCE_MAX_AGE_SECONDS = 90   # Use cached balance only if fresh (90 s max staleness)

# Balance timing race protection: minimum age (seconds) the balance must have
# been updated within before entry is allowed.  On startup and after broker
# reconnects the balance can take 21–60 s to settle; blocking entries during
# this window prevents sizing decisions based on a stale or missing balance.
# Set via env var BALANCE_STABLE_SECONDS (default 60 s).
BALANCE_STABLE_SECONDS: int = int(os.getenv('BALANCE_STABLE_SECONDS', '60'))

# Cycle-level safety cap: if the full trading cycle (balance + positions + scan)
# takes longer than this, the scan loop breaks early to protect cycle cadence.
# Worst-case (no cache hits): 100 markets × 8s scan delay ≈ 800s; cap at 900s.
# With the cache-aware delay (skips sleep on cache hits) the actual runtime is
# typically well below this ceiling, allowing more markets to be evaluated per cycle.
MAX_CYCLE_SECONDS = 900  # Hard cap on total cycle duration (seconds; raised from 600s)
# Separate cap for the scan portion only (measured from just before the scan loop).
# This prevents pre-scan overhead (balance fetch, position management) from eating
# into the scan budget and triggering 0-market cycles.
MAX_SCAN_SECONDS = 350   # Max seconds allowed for the market scan loop itself (raised from 120 → 210 → 350)
# Hard cap on position-analysis time (the pre-scan phase).
# pykrakenapi 0.3.2 retries indefinitely on RemoteDisconnected; even with the 15s
# per-call thread timeout each position costs up to 15s.  With this guard, the
# position loop will skip any remaining positions once the budget is exhausted
# so the bot always reaches the market scan within a predictable window.
PRE_SCAN_POSITION_BUDGET_SECONDS = 90  # Max seconds for the position-analysis loop

# Market scanning rotation (prevents scanning same markets every cycle)
