# OPTION 3 (BEST LONG-TERM): Dynamic minimum based on balance
# MIN_TRADE_USD = max(10.00, balance * 0.15)
# This scales automatically with account size:
# - $20 account: min trade = $10.00 (15% would be $3.00, floor enforced)
# - $50 account: min trade = $10.00 (15% would be $7.50, floor enforced)
# - $70 account: min trade = $10.50 (15% of $70)
# - $100 account: min trade = $15.00 (15% of $100)
# Minimum $1 per position – allows tiny positions when required.
# ⚠️  Positions under $10 face significant fee pressure (~1.4% round-trip on Coinbase).
# Raise this value (e.g. to 10.0) on well-funded accounts for better fee efficiency.
BASE_MIN_POSITION_SIZE_USD = 1.0  # Floor minimum ($1 - allows tiny positions when required)
DYNAMIC_POSITION_SIZE_PCT = 0.35  # 35% of balance per position (moderate/aggressive: 0.25→0.35)
POSITION_SIZE_WARNING_THRESHOLD_USD = 10.0  # Warn when position is under this amount (near recommended minimum)

# OPTION B: Brokerage-specific minimum trade sizes
# Any trade that would create a position below this threshold is skipped,
# preventing dust positions at creation time.
# Values reflect actual exchange minimums; raise per-broker entries for stricter
# fee-efficiency enforcement on well-funded accounts.
BROKERAGE_MIN_TRADE_USD: dict = {
    'coinbase': 5.0,    # Coinbase fee-efficiency floor ($5 minimum)
    'kraken':   10.5,   # Kraken exchange minimum ($10.50 — enforced to keep trades eligible)
    'binance':  1.0,    # Binance actual minimum; was $10
    'okx':      1.0,    # OKX actual minimum; was $10
    'alpaca':   1.0,    # Alpaca minimum (stocks, lower fees)
}

def get_dynamic_min_position_size(balance: float, broker_name: str = '') -> float:
    """
    Calculate dynamic minimum position size based on account balance and
    brokerage-specific minimums (Option B – prevent dust at trade creation).

    Formula: min_trade_usd = max(BASE_MIN_POSITION_SIZE_USD,
                                 account_balance * min_trade_pct,
                                 brokerage_minimum)

    Args:
        balance: Current account balance in USD
        broker_name: Name of the active broker (e.g. 'coinbase', 'kraken').
                     Used to enforce exchange-specific minimum order sizes.
                     Pass an empty string to use the global floor only.

    Returns:
        Minimum position size in USD (never below BASE_MIN_POSITION_SIZE_USD
        or the broker's own minimum, whichever is larger)

    Raises:
        ValueError: If balance is negative
    """
    if balance < 0:
        raise ValueError(f"Balance cannot be negative: {balance}")

    # Look up brokerage-specific minimum (default to BASE_MIN_POSITION_SIZE_USD)
    brokerage_min = BROKERAGE_MIN_TRADE_USD.get(
        broker_name.lower() if broker_name else '',
        BASE_MIN_POSITION_SIZE_USD,
    )

    # Enforce: max(MIN_POSITION_USD floor, base floor, balance-based dynamic, brokerage minimum)
    # MIN_POSITION_USD is the absolute hard floor (prevents any sub-$5 entry regardless of config)
    return max(MIN_POSITION_USD, BASE_MIN_POSITION_SIZE_USD, balance * DYNAMIC_POSITION_SIZE_PCT, brokerage_min)


def get_tradable_min_size(broker_name: str = '') -> float:
    """
    Return the minimum USD notional for a position to be counted as tradable.

    Looks up the exchange-specific floor in ``TRADABLE_MIN_POSITION_BY_BROKER``
    (using a normalised, lower-case key) and falls back to the global
    ``MIN_TRADABLE_POSITION_USD`` when the broker is unknown.

    This is the single authoritative lookup used by ``filter_tradable_positions``
    and by log messages so the logged threshold always matches the filter.
    """
    return TRADABLE_MIN_POSITION_BY_BROKER.get(
        broker_name.lower() if broker_name else '',
        MIN_TRADABLE_POSITION_USD,
    )


def filter_tradable_positions(positions: list, broker_name: str = '') -> list:
    """
    "Tradable Positions Only" filter.

    Returns the subset of *positions* whose ``size_usd`` value meets the
    exchange-specific (or global) minimum required for a position to be
    considered open and tradable.  Positions below the threshold are dust:
    they cannot be meaningfully managed or exited and must not count toward
    position-cap checks, first-trade gates, or open-position counters.

    Args:
        positions:   Raw list of position dicts (each must have a ``size_usd`` key).
        broker_name: Active broker/exchange name (e.g. ``'coinbase'``).
                     Used to look up the exchange-specific floor via
                     ``get_tradable_min_size``; falls back to
                     ``MIN_TRADABLE_POSITION_USD`` when not found.

    Returns:
        Filtered list containing only positions whose ``size_usd`` (coerced to
        ``float``) is ``>= min_size``.  Order is preserved.
    """
    min_size: float = get_tradable_min_size(broker_name)
    return [p for p in positions if float(p.get('size_usd') or 0) >= min_size]


def get_balance_based_max_positions(balance: float) -> int:
    """
    Return the maximum number of concurrent open positions allowed for the
    given account balance.

    Uses the CapitalTierHierarchy for smooth, tier-based scaling so the
    position cap grows proportionally with account size:

      STARTER  ($50–99):    max 2–5 positions (18% per position → 90% max exposure)
      SAVER    ($100–249):  max 2–3 positions
      INVESTOR ($250–999):  max 3–5 positions
      INCOME   ($1k–5k):    max 5–7 positions
      LIVABLE  ($5k–25k):   max 7–10 positions
      BALLER   ($25k+):     max 10–15 positions (capped at MAX_TOTAL_POSITIONS = 10)

    Micro-cap accounts (balance < BALANCE_THRESHOLD_MICRO = $50) are pinned
    to 1 position so the compounding engine can concentrate capital.
    Accounts above $50 scale to 2–5+ positions via CapitalTierHierarchy.

    The returned value is always capped at MAX_TOTAL_POSITIONS.

    Args:
        balance: Current account balance in USD (≥ 0).

    Returns:
        Maximum allowed concurrent positions (int, 1 – MAX_TOTAL_POSITIONS).
    """
    if balance < 0:
        logger.warning(
            "get_balance_based_max_positions: negative balance %.2f detected "
            "(possible API error) – treating as 0.0",
            balance,
        )
        balance = 0.0

    # Micro-cap: pin to 1 position (maximum capital concentration for compounding)
    if balance < BALANCE_THRESHOLD_MICRO:
        return 1

    # Tier-hierarchy scaling for larger balances
    if CAPITAL_TIER_HIERARCHY_AVAILABLE and _tier_get_max_positions is not None:
        cap = _tier_get_max_positions(balance)
    else:
        # Fallback: simple ladder if capital_tier_hierarchy module unavailable
        if balance < BALANCE_THRESHOLD_SMALL:
            cap = 5  # STARTER/SAVER range: up to 5 positions at 18% each
        elif balance < 1000.0:
            cap = 3
        elif balance < 5000.0:
            cap = 5
        else:
            cap = 7

    # Never exceed the global hard cap
    return min(cap, MAX_TOTAL_POSITIONS)

